    def size
      return @size if defined?(@size)

      height, width = `/bin/stty size 2>/dev/null`.presence&.split&.map(&:to_i)
      return if height.nil? || width.nil?

      @size = T.let([height, width], T.nilable([Integer, Integer]))
    end

    sig { returns(Integer) }
    def height
      @height ||= T.let(size&.first || `/usr/bin/tput lines 2>/dev/null`.presence&.to_i || 40, T.nilable(Integer))
    end

    # Keep in sync with `columns` in Library/Homebrew/utils/tty.sh.
    sig { returns(Integer) }
    def width
      @width ||= T.let(size&.second || `/usr/bin/tput cols 2>/dev/null`.presence&.to_i || 80, T.nilable(Integer))
    end

    sig { params(string: String).returns(String) }
    def truncate(string)
      (w = width).zero? ? string.to_s : (string.to_s[0, w - 4] || "")
    end

def initialize(version)
    raise MacOSVersion::Error, version unless /\A\d{2,}(?:\.\d+){0,2}\z/.match?(version)

    super(T.must(version))

    @comparison_cache = T.let({}, T::Hash[T.untyped, T.nilable(Integer)])
    @pretty_name = T.let(nil, T.nilable(String))
    @sym = T.let(nil, T.nilable(Symbol))
  end

  sig { override.params(other: T.untyped).returns(T.nilable(Integer)) }
  def <=>(other)
    return @comparison_cache[other] if @comparison_cache.key?(other)

    result = case other
    when Symbol
      if SYMBOLS.key?(other) && to_sym == other
        0
      else
        v = SYMBOLS.fetch(other) { other.to_s }
        super(v)
      end
    else
      super
    end

    @comparison_cache[other] = result unless frozen?

    result
  end
